const item = $input.first().json;
const now = new Date();
const iso = now.toISOString();
const stamp = iso.replace(/[:.]/g, '-');
const date = iso.slice(0, 10);
let content = item.choices && item.choices[0] ? item.choices[0].message.content : null;
let verdict = 'WARN';
if (!content) {
  content = '# Local Worker Report\n\n## Verdict\nFAIL: Ollama did not return a completion.\n\n## Raw Error\n\n```json\n' + JSON.stringify(item, null, 2).slice(0, 3000) + '\n```';
} else if (/\bPASS\b/.test(content.slice(0, 250))) {
  verdict = 'PASS';
}
const report = '<!-- generated by: Local Ollama Reviewer - 5 Minute Loop -->\n<!-- generated_at: ' + iso + ' -->\n\n' + content.trim() + '\n';
const reportPath = 'reports/local-worker/' + date + '/' + stamp + '.md';
return [{ json: { report, report_base64: Buffer.from(report, 'utf8').toString('base64'), report_path: reportPath, generated_at: iso, verdict } }];
